-- Aula 19: Criando APIs REST
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Simular Rota GET',
  'description', 'Crie uma função que simula uma rota GET retornando JSON.',
  'initialCode', '// Crie uma função que retorna um objeto JSON\nfunction get(rota) {\n  return { rota: rota, metodo: "GET" };\n}\n\nconsole.log(JSON.stringify(get("/users")));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function get(rota) { return { rota: rota, metodo: "GET" }; } console.log(JSON.stringify(get("/users")));', 'expected', '{"rota":"/users","metodo":"GET"}')
  )
) WHERE id = 19;

-- Aula 20: Middlewares
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Criar Middleware',
  'description', 'Crie uma função middleware que processa uma requisição.',
  'initialCode', '// Crie um middleware que adiciona timestamp\nfunction middleware(req) {\n  req.timestamp = Date.now();\n  return req;\n}\n\nconst req = { url: "/api" };\nconsole.log(middleware(req).timestamp > 0);\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function middleware(req) { req.timestamp = Date.now(); return req; } const req = { url: "/api" }; console.log(middleware(req).timestamp > 0);', 'expected', 'true')
  )
) WHERE id = 20;

-- Aula 21: Autenticação JWT
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Gerar Token Simples',
  'description', 'Crie uma função que gera um token simples.',
  'initialCode', '// Crie uma função que retorna um token codificado\nfunction gerarToken(userId) {\n  return "token_" + userId;\n}\n\nconsole.log(gerarToken(123));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function gerarToken(userId) { return "token_" + userId; } console.log(gerarToken(123));', 'expected', 'token_123')
  )
) WHERE id = 21;

-- Aula 22: Padrões de Projeto
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Implementar Singleton',
  'description', 'Crie uma classe Singleton simples.',
  'initialCode', '// Crie uma classe que retorna sempre a mesma instância\nclass Singleton {\n  static instance = null;\n  static getInstance() {\n    if (!Singleton.instance) {\n      Singleton.instance = new Singleton();\n    }\n    return Singleton.instance;\n  }\n}\n\nconst a = Singleton.getInstance();\nconst b = Singleton.getInstance();\nconsole.log(a === b);\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'class Singleton { static instance = null; static getInstance() { if (!Singleton.instance) { Singleton.instance = new Singleton(); } return Singleton.instance; } } const a = Singleton.getInstance(); const b = Singleton.getInstance(); console.log(a === b);', 'expected', 'true')
  )
) WHERE id = 22;

-- Aula 23: Clean Architecture
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Separar Camadas',
  'description', 'Crie funções que representam diferentes camadas da arquitetura.',
  'initialCode', '// Crie funções para Controller, UseCase e Repository\nfunction controller() { return "Controller"; }\nfunction useCase() { return "UseCase"; }\nfunction repository() { return "Repository"; }\n\nconsole.log(controller());\nconsole.log(useCase());\nconsole.log(repository());\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function controller() { return "Controller"; } function useCase() { return "UseCase"; } function repository() { return "Repository"; } console.log(controller()); console.log(useCase()); console.log(repository());', 'expected', 'Controller\nUseCase\nRepository')
  )
) WHERE id = 23;

-- Aula 24: Microserviços
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Simular Microserviço',
  'description', 'Crie uma função que simula um microserviço.',
  'initialCode', '// Crie uma função que retorna dados de um serviço\nfunction microservico(nome) {\n  return { servico: nome, status: "online" };\n}\n\nconsole.log(JSON.stringify(microservico("auth")));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function microservico(nome) { return { servico: nome, status: "online" }; } console.log(JSON.stringify(microservico("auth")));', 'expected', '{"servico":"auth","status":"online"}')
  )
) WHERE id = 24;

-- Aula 25: Docker Básico
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Gerar Dockerfile',
  'description', 'Crie uma função que gera comandos Docker.',
  'initialCode', '// Crie uma função que retorna comandos Docker\nfunction dockerfile(imagem) {\n  return `FROM ${imagem}`;\n}\n\nconsole.log(dockerfile("node:18"));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function dockerfile(imagem) { return `FROM ${imagem}`; } console.log(dockerfile("node:18"));', 'expected', 'FROM node:18')
  )
) WHERE id = 25;

-- Aula 26: CI/CD
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Pipeline Simples',
  'description', 'Crie uma função que simula etapas de um pipeline.',
  'initialCode', '// Crie uma função que retorna as etapas do pipeline\nfunction pipeline() {\n  return ["build", "test", "deploy"];\n}\n\nconsole.log(pipeline().join(" -> "));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function pipeline() { return ["build", "test", "deploy"]; } console.log(pipeline().join(" -> "));', 'expected', 'build -> test -> deploy')
  )
) WHERE id = 26;

-- Aula 27: Monitoramento
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Sistema de Logs',
  'description', 'Crie uma função que registra logs com timestamp.',
  'initialCode', '// Crie uma função que retorna um log formatado\nfunction log(mensagem) {\n  return `[LOG] ${mensagem}`;\n}\n\nconsole.log(log("Sistema iniciado"));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function log(mensagem) { return `[LOG] ${mensagem}`; } console.log(log("Sistema iniciado"));', 'expected', '[LOG] Sistema iniciado')
  )
) WHERE id = 27;

